external_knowledge:
- 'labels' refers to 'sensor_name';
- 'climate details' refer to 'temperature' and 'humidity';
- 'devices' refers to 'sensor_id';
- 'recorded environmental conditions' implies there's a match in sensor ID between the sensors and sensor_readings tables.

sql:
SELECT results_summary
FROM data_analysis
WHERE method_used = 'Correlation Analysis';

SELECT COUNT(*)
FROM sensors
WHERE location_id = 5;

SELECT AVG(temperature) AS average_temperature
FROM sensor_readings
WHERE sensor_id = 0;

SELECT COUNT(sensor_id) AS NumberOfSensors 
FROM sensors 
WHERE location_id = 0;

SELECT sensor_id, temperature
FROM sensor_readings
WHERE temperature IS NOT NULL;

SELECT project_id
FROM research_projects
WHERE project_name LIKE '%Control%';

external_knowledge:
- "daily dawn and dusk of our environmental tale" refers to the date derived from the timestamp;
- "average warmth and moisture" corresponds to the average temperature and humidity;
- "adorned the atmosphere" is a metaphorical way of saying the environmental readings were taken.

sql:
SELECT SUBSTR(timestamp, 1, 10) AS date, AVG(temperature) AS average_temperature, AVG(humidity) AS average_humidity
FROM sensor_readings
GROUP BY date;

SELECT COUNT(DISTINCT sensor_id) AS total_calibrated_sensors_last_30_days
FROM sensor_calibrations
WHERE calibration_date >= date('now', '-30 days');
